function OldForm() {
  const [loading, setLoading] = useState(false);
  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    await fetch('/api/submit', {
      method: 'POST',
      body: new FormData(e.target)
    });
    setLoading(false);
  };
  return <form onSubmit={handleSubmit}>...</form>;
}

